page_settings.custom_css:
:root{--g-deep:#08170e;--g-forest:#12261B;--g-mid:#1c3d28;--g-rich:#214B33;--g-light:#2d6644;--mint:#9AE6B4;--mint-dim:rgba(154,230,180,.12);--cyan:#B7FFE4;--blue:#0285FF;--blue-glow:rgba(2,133,255,.25);--cream:#FBF9F3;--cream-warm:#F4EFE4;--navy:#000D32;--muted:rgba(255,255,255,.6);--muted-dark:rgba(0,13,50,.6);--r-sm:8px;--r-md:16px;--r-lg:24px;}
.hbs-mint-gradient{background:linear-gradient(130deg,var(--mint) 0%,var(--cyan) 100%);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;}
.hbs-dot-grid{background-image:radial-gradient(circle,rgba(154,230,180,.1) 1px,transparent 1px);background-size:30px 30px;}
.hbs-badge{display:inline-flex;align-items:center;gap:.5rem;padding:.4rem 1rem .4rem .65rem;border-radius:100px;background:rgba(154,230,180,.09);border:1px solid rgba(154,230,180,.22);margin-bottom:1.75rem;}
.hbs-badge-dot{width:7px;height:7px;border-radius:50%;background:var(--mint);display:inline-block;animation:bdot 2.2s ease infinite;}
@keyframes bdot{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.45;transform:scale(.75)}}
.hbs-vsl-wrap{max-width:840px;margin:0 auto 2.75rem;border-radius:24px;overflow:hidden;box-shadow:0 32px 90px rgba(0,0,0,.55),0 0 0 1px rgba(154,230,180,.13);}
.hbs-vsl-ratio{position:relative;padding-bottom:56.25%;background:var(--g-deep);}
.hbs-vsl-inner{position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:1rem;background:linear-gradient(135deg,#0b1c11 0%,#183024 100%);}
.hbs-play{width:88px;height:88px;border-radius:50%;background:rgba(255,255,255,.1);border:2px solid rgba(255,255,255,.25);display:flex;align-items:center;justify-content:center;transition:all .3s;backdrop-filter:blur(8px);}
.hbs-play svg{width:34px;height:34px;margin-left:5px;}
.hbs-eyebrow{display:inline-flex;align-items:center;gap:.6rem;margin-bottom:1.25rem;}
.hbs-eyebrow-line{width:22px;height:2px;background:var(--mint);border-radius:2px;display:inline-block;}
.hbs-eyebrow-line-dark{background:var(--g-rich);}
.hbs-prob-card{padding:2rem;border-radius:16px;background:rgba(8,23,14,.55);border:1px solid rgba(154,230,180,.11);position:relative;overflow:hidden;transition:transform .3s,border-color .3s;height:100%;}
.hbs-prob-icon{width:46px;height:46px;border-radius:12px;background:var(--mint-dim);display:flex;align-items:center;justify-content:center;margin-bottom:1.25rem;}
.hbs-testi-card{padding:2rem;border-radius:16px;background:rgba(255,255,255,.05);border:1px solid rgba(154,230,180,.13);position:relative;overflow:hidden;transition:all .3s;height:100%;}
.hbs-testi-card blockquote{font-size:.93rem;color:rgba(255,255,255,.78);line-height:1.72;font-style:italic;margin-bottom:1.5rem;}
.hbs-stars{color:#FFD55C;font-size:.95rem;margin-bottom:1rem;}
.hbs-author-av{width:42px;height:42px;border-radius:50%;background:linear-gradient(135deg,var(--g-rich),var(--mint));display:inline-flex;align-items:center;justify-content:center;font-size:.75rem;font-weight:600;color:var(--g-forest);vertical-align:middle;}
.hbs-res-card{border-radius:16px;overflow:hidden;background:white;border:1px solid rgba(33,75,51,.09);box-shadow:0 4px 18px rgba(0,0,0,.05);transition:all .3s;height:100%;}
.hbs-res-thumb{height:140px;display:flex;align-items:flex-end;padding:1rem;}
.hbs-res-cat{padding:.28rem .7rem;background:var(--mint);color:var(--g-forest);font-size:.67rem;letter-spacing:.1em;text-transform:uppercase;border-radius:100px;font-weight:600;font-family:Oswald,sans-serif;}
.hbs-cred{display:flex;align-items:center;gap:.75rem;font-size:.93rem;color:rgba(0,13,50,.75);margin-bottom:.7rem;}
.hbs-cred-check{width:20px;height:20px;border-radius:50%;flex-shrink:0;background:linear-gradient(135deg,var(--g-rich),var(--mint));display:inline-flex;align-items:center;justify-content:center;color:white;font-size:.7rem;font-weight:700;}
.hbs-btn-mint{display:inline-flex;align-items:center;gap:.5rem;padding:1.1rem 2.25rem;border-radius:100px;font-size:1.05rem;font-weight:600;cursor:pointer;background:linear-gradient(135deg,var(--mint) 0%,var(--cyan) 100%);color:var(--g-forest);box-shadow:0 8px 32px rgba(154,230,180,.3);text-decoration:none;transition:all .25s;}
.hbs-btn-ghost{display:inline-flex;align-items:center;gap:.5rem;padding:1.1rem 2.25rem;border-radius:100px;font-size:1.05rem;font-weight:600;cursor:pointer;background:transparent;color:var(--mint);border:1.5px solid rgba(154,230,180,.4);text-decoration:none;transition:all .25s;}
.hbs-btn-mint:hover,.hbs-btn-ghost:hover{transform:translateY(-2px);}.hbs-res-card:hover,.hbs-prob-card:hover,.hbs-testi-card:hover{transform:translateY(-4px);}.hbs-faq summary{cursor:pointer;}
